#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10;

struct Edge{
    int to,val;
};

int n,q,c[N],dep[N],p[N][21];
long long dis[N][21],f[N][21],dp[N][2];
vector<Edge> g[N];

void dfs1(int x,int fa){
    dp[x][0]=c[x];
    for(int i=0;i<g[x].size();i++)
        if(g[x][i].to!=fa){
            dfs1(g[x][i].to,x);
            dp[x][0]=max(dp[x][0],dp[g[x][i].to][0]-2*g[x][i].val);
        }
}

void dfs2(int x,int fa,int fd){
    if(x==1)
        dp[x][1]=dp[x][0];
    else
        dp[x][1]=max(dp[x][0],dp[fa][1]-2*fd);
    for(int i=0;i<g[x].size();i++)
        if(g[x][i].to!=fa)
            dfs2(g[x][i].to,x,g[x][i].val);
}

void dfs3(int x,int fa){
    dep[x]=dep[fa]+1;
    for(int i=0;i<g[x].size();i++)
        if(g[x][i].to!=fa){
            int v=g[x][i].to;
            dis[v][0]=g[x][i].val,f[v][0]=max(dp[v][1],dp[x][1]),p[v][0]=x;
            for(int j=1;p[p[v][j-1]][j-1];j++){
                p[v][j]=p[p[v][j-1]][j-1];
                dis[v][j]=dis[p[v][j-1]][j-1]+dis[v][j-1];
                f[v][j]=max(f[v][j-1],f[p[v][j-1]][j-1]);
            }
            dfs3(v,x);
        }
}

long long LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    long long ans=c[x]+c[y],mx=dp[x][1];
    for(int i=20;i>=0;i--)
        if(dep[p[x][i]]>=dep[y])
            ans-=dis[x][i],mx=max(mx,f[x][i]),x=p[x][i];
    if(x==y)
        return ans+mx;
    for(int i=20;i>=0;i--)
        if(p[x][i]!=p[y][i])
            ans-=dis[x][i]+dis[y][i],mx=max(mx,max(f[x][i],f[y][i])),x=p[x][i],y=p[y][i];
    ans-=dis[x][0]+dis[y][0],mx=max(mx,max(f[x][0],f[y][0])),x=p[x][0],y=p[y][0];
    return ans+mx;
}

int main(){
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++)
        scanf("%d",&c[i]);
    for(int i=1,u,v,w;i<n;i++){
        scanf("%d%d%d",&u,&v,&w);
        g[u].push_back({v,w});
        g[v].push_back({u,w});
    }
    dfs1(1,0);
    dfs2(1,0,0);
    dfs3(1,0);
    while(q--){
        int x,y;
        scanf("%d%d",&x,&y);
        printf("%lld\n",LCA(x,y));
    }
    return 0;
}
